/bin/bash -lc "python - <<'PY'
import os
for root, dirs, files in os.walk('.'):
    for f in files:
        p=os.path.join(root,f)
        try:
            with open(p,'rb') as fh:
                b=fh.read(256)
            if any(x not in b'\\x00\\t\\n\\r' and (x<32 or x>126) for x in b):
                kind='bin'
            else:
                kind='txt'
            print(kind, p)
        except Exception as e:
            print('ERR',p,e)
PY"

